module dram_cell(  
    input wire D,  
    input wire WL,  
    input wire clk,  
    output reg Q  
);  
    reg stored_data;  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (WL) begin  
            stored_data <= D;  
        end  
        Q <= stored_data;  
    end  
endmodule
